def generate_ui_scaffold(spec):
    """Generate a UI scaffold file from specification."""
    try:
        content = UI_SCAFFOLD_TEMPLATE.format(**spec)
        
        # Write to file
        ui_dir = Path(__file__).parent.parent / "ui"
        file_path = ui_dir / spec["file_name"]
        
        with open(file_path, 'w', encoding='utf-8') as f:
            f.write(content)
        
        print(f"✓ Generated {spec['file_name']}")
        return True
    except Exception as e:
        print(f"✗ Failed to generate {spec['file_name']}: {e}")
        return False


def main():
    """Generate all UI scaffolds."""
    print("Generating Phase B UI Scaffolds...\n")
    
    success_count = 0
    fail_count = 0
    
    for spec in MODULES_SPEC:
        if generate_ui_scaffold(spec):
            success_count += 1
        else:
            fail_count += 1
    
    print(f"\nGeneration complete:")
    print(f"  ✓ Success: {success_count}")
    print(f"  ✗ Failed: {fail_count}")
    
    return fail_count == 0


if __name__ == "__main__":
    import sys
    sys.exit(0 if main() else 1)
